//! Manifest type: auto-generated metadata for a dataset's files.
//!
//! The manifest captures the full hierarchy:
//!   format (parquet, vortex, ...) → table (lineitem, orders, ...) → files
//!
//! It is generated by scanning the dataset's `data/` directory and hashing
//! each file. The manifest is written to `manifest.json` both locally and in S3.

use std::collections::BTreeMap;
use std::path::Path;

use anyhow::Context;
use anyhow::Result;
use serde::Deserialize;
use serde::Serialize;
use sha2::Digest;
use sha2::Sha256;

/// Auto-generated manifest describing all files in a dataset.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Manifest {
    /// Schema version.
    pub version: u32,
    /// Dataset name (must match `dataset.yaml`).
    pub name: String,
    /// Formats available, keyed by format name (e.g. "parquet", "vortex").
    pub formats: BTreeMap<String, FormatEntry>,
}

/// All tables available in a given format.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FormatEntry {
    /// Tables in this format, keyed by table name.
    pub tables: BTreeMap<String, TableEntry>,
}

/// All files for a single table in a single format.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TableEntry {
    /// Files belonging to this table.
    pub files: Vec<FileEntry>,
}

/// A single data file with its content hash and size.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FileEntry {
    /// Relative path from the dataset root (e.g. "parquet/lineitem/lineitem_000.parquet").
    pub path: String,
    /// SHA-256 hex digest of the file contents.
    pub sha256: String,
    /// File size in bytes.
    pub size_bytes: u64,
}

impl Manifest {
    /// Create a new empty manifest.
    pub fn new(name: impl Into<String>) -> Self {
        Self {
            version: 1,
            name: name.into(),
            formats: BTreeMap::new(),
        }
    }

    /// Add a file entry under the given format and table.
    pub fn add_file(&mut self, format: &str, table: &str, file: FileEntry) {
        self.formats
            .entry(format.to_string())
            .or_insert_with(|| FormatEntry {
                tables: BTreeMap::new(),
            })
            .tables
            .entry(table.to_string())
            .or_insert_with(|| TableEntry { files: Vec::new() })
            .files
            .push(file);
    }

    /// Total size across all formats, tables, and files.
    pub fn total_size_bytes(&self) -> u64 {
        self.formats
            .values()
            .flat_map(|f| f.tables.values())
            .flat_map(|t| &t.files)
            .map(|f| f.size_bytes)
            .sum()
    }

    /// Total number of files.
    pub fn total_files(&self) -> usize {
        self.formats
            .values()
            .flat_map(|f| f.tables.values())
            .map(|t| t.files.len())
            .sum()
    }

    /// Iterate over all file entries with their format and table names.
    pub fn iter_files(&self) -> impl Iterator<Item = (&str, &str, &FileEntry)> {
        self.formats.iter().flat_map(|(format, fe)| {
            fe.tables.iter().flat_map(move |(table, te)| {
                te.files
                    .iter()
                    .map(move |f| (format.as_str(), table.as_str(), f))
            })
        })
    }

    /// Serialize to JSON bytes.
    pub fn to_json(&self) -> Result<Vec<u8>> {
        Ok(serde_json::to_vec_pretty(self)?)
    }

    /// Deserialize from JSON bytes.
    pub fn from_json(bytes: &[u8]) -> Result<Self> {
        Ok(serde_json::from_slice(bytes)?)
    }

    /// Compute the SHA-256 hash of the serialized manifest.
    pub fn content_hash(&self) -> Result<String> {
        let bytes = self.to_json()?;
        let hash = Sha256::digest(&bytes);
        Ok(hex_encode(&hash))
    }
}

/// Compute SHA-256 hash of a file on disk, streaming to avoid loading into memory.
pub fn hash_file(path: impl AsRef<Path>) -> Result<(String, u64)> {
    let path = path.as_ref();
    let mut file =
        std::fs::File::open(path).with_context(|| format!("opening {}", path.display()))?;
    let mut hasher = Sha256::new();
    let size = std::io::copy(&mut file, &mut hasher)
        .with_context(|| format!("reading {}", path.display()))?;
    let hash = hex_encode(&hasher.finalize());
    Ok((hash, size))
}

fn hex_encode(bytes: &[u8]) -> String {
    use std::fmt::Write;
    bytes.iter().fold(String::new(), |mut s, b| {
        let _ = write!(s, "{b:02x}");
        s
    })
}
